Also this bit:

```python
def ast2expr(ast):
    """Convert an abstract syntax tree to an Expression."""
    if ast[0] == 'const':
        return _CONSTS[ast[1]]
    elif ast[0] == 'var':
        return exprvar(ast[1], ast[2])
    else:
        xs = [ast2expr(x) for x in ast[1:]]
        return ASTOPS[ast[0]](*xs, simplify=False)
```

The comparison to `'var'` isn't right; it looks like it should be comparing to `'lit'`.

Thanks @paulfitz. I found that adding `-DHXCPP_VISIT_ALLOCS` solved the particular compile error above. In case it is of use to others...

After setting up a recent version of Haxe on Ubuntu 14.04 I created a `libdaff.a` like so:

```sh
git clone git@github.com:paulfitz/daff
cd daff
make cpp
ar rc bin/libdaff.a bin/obj/linux64-debug/*.o
```

My `Makefile` then looks like this:
```
all:
	g++ --std=c++11 -DHXCPP_VISIT_ALLOCS -I../daff/bin/include -I/usr/share/haxelib/hxcpp/3,2,205/include -omain.exe main.cpp \
		-L../daff/bin/ -ldaff -lpthread -ldl
```

To compile the following getting-to-know-daff example:

```cpp
#include <stdio.h>

#define HX_DECLARE_MAIN 1
#include <hxcpp.h>

#include <iostream>

#include <coopy/SimpleTable.h>
#include <coopy/SimpleCell.h>
#include <coopy/Coopy.h>
#include <coopy/Alignment.h>
#include <coopy/CompareTable.h>
#include <coopy/CompareFlags.h>
#include <coopy/TableDiff.h>
#include <coopy/DiffRender.h>
#include <coopy/TerminalDiffRender.h>

int my_main() {
    using namespace coopy;

    // Two 2x3 tables
    SimpleTable t1 = SimpleTable_obj::__new(3,2);
    SimpleTable t2 = SimpleTable_obj::__new(3,2);
    // Set their cells to the same values
    std::string values[2][3] = {
        {"A1","B1","C1"},
        {"A2","B2","C2"}
    };
    for (auto col : {0,1,2}) {
        for (auto row : {0,1}) {
            auto cell = SimpleCell_obj::__new(String(values[row][col].c_str()));
            t1->setCell(col,row,cell);
            t2->setCell(col,row,cell);
        }
    }
    // Create a difference
    t2->setCell(1,1,SimpleCell_obj::__new(String("foo")));

    // Do table comparison
    CompareFlags flags = CompareFlags_obj::__new();
    CompareTable cmp = Coopy_obj::compareTables(t1,t2,flags);

    // Create a table diff
    Alignment alignment = cmp->align();
    TableDiff table_diff = TableDiff_obj::__new(alignment,flags);
    SimpleTable table_diff_output = SimpleTable_obj::__new(0,0);
    table_diff->hilite(table_diff_output);

    // Output difference as plain string
    std::cout << table_diff_output->toString().__CStr() << std::endl;

    // Render difference as coloured terminal
    TerminalDiffRender tdr = TerminalDiffRender_obj::__new(flags);
    std::cout << tdr->render(table_diff_output).__CStr() << std::endl;

    // Render difference as HTML
    DiffRender hdr = DiffRender_obj::__new();
    hdr->render(table_diff_output);
    std::cout << hdr->html().__CStr() << std::endl;

    return 0;
}

// Necessary for Haxe threading to work
HX_BEGIN_MAIN
my_main();
HX_END_MAIN
```

