The following code prints me an empty message `<message id=''>{}</message>` where I expect something like described [in the documentation](https://firebase.google.com/docs/cloud-messaging/server#format): `<message id=""><gcm xmlns="google:mobile:data">{...JSON payload....}</gcm></message>`.

```python
import asyncio, datetime, uuid, logging, json, aioxmpp.xso, aioxmpp.utils, aioxmpp.node, aioxmpp.security_layer, aioxmpp.stanza, aioxmpp.structs
from . import settings

class FCMPayload(aioxmpp.xso.XSO):
    TAG = (aioxmpp.utils.namespaces.client, "gcm")
    xmlns = aioxmpp.xso.Attr(tag="xmlns", default="google:mobile:data")
    text = aioxmpp.xso.Text(default=None)

    def __repr__(self):
        return '<gcm xmlns={!r}>{!s}</gcm>'.format(self.xmlns, self.text)

class FCMMessage(aioxmpp.stanza.StanzaBase):
    TAG = (aioxmpp.utils.namespaces.client, "message")
    id_ = aioxmpp.xso.Attr(tag="id", default="")
    payload = aioxmpp.xso.ChildTextMap(FCMPayload)

    def __repr__(self):
        return '<message id={!r}>{!r}</message>'.format(self.id_, self.payload)

async def main(jid, password, recipient):
    @asyncio.coroutine
    def get_password(client_jid, nattempt):
        return None if nattempt > 1 else password

    client = aioxmpp.node.PresenceManagedClient(
        jid,
        aioxmpp.security_layer.tls_with_password_based_authentication(get_password),
        override_peer = [(settings.FCM_SERVER_URL, settings.FCM_SERVER_PORT, aioxmpp.connector.XMPPOverTLSConnector())],
    ) 

    async with aioxmpp.node.UseConnected(client, timeout=datetime.timedelta(seconds=30)) as stream:
        payload = json.dumps({
            "message_id": str(uuid.uuid4()),
            "to": settings.RECIPIENT,
            "notification": { 
                "title": "Hello",
                "text": "World",
            } 
        })

        msg = FCMMessage()
        msg.payload.text = payload
        print(msg)
        await stream.send_and_wait_for_sent(msg)

if __name__ == "__main__":
    logging.basicConfig(level=logging.DEBUG, format='%(levelname)-7s %(module)s:%(lineno)-4s %(message)s')
    jid = aioxmpp.structs.JID.fromstr(settings.FCM_JID)
    recipient = aioxmpp.structs.JID.fromstr(settings.RECIPIENT)
    asyncio.get_event_loop().run_until_complete(main(jid, settings.FCM_API_KEY, recipient))
```

